from zeep import Client
from zeep.exceptions import Fault

def main():
    wsdl_url = 'https://third-party-insurance-service.com/api?wsdl'
    client = Client(wsdl_url)

    policy_number = input("Enter Policy Number: ")
    customer_name = input("Enter Customer Name: ")

    try:
        response = client.service.lookupPolicy(PolicyNumber=policy_number, CustomerName=customer_name)
        print("Policy Details:", response)
    except Fault as e:
        print("Error:", e)

if __name__ == "__main__":
    main()